class Solution:
    def makeTheIntegerZero(self, num1: int, num2: int) -> int:
        target = num1
        for k in range(1, 61):
            val = target - k * num2
            if val < 0:
                continue
            bits = bin(val).count('1')
            if bits <= k <= val:
                return k
        return -1

